export default function ShapeDivider({ value, onChange }: any) {
  const current = {
    enabled: false,
    position: "bottom",
    shape: "wave",
    color: "#ffffff",
    colorType: "solid",
    gradient: {
      color1: "#ffffff",
      location1: 0,
      color2: "#f5f5f5",
      location2: 100,
      angle: 180,
    },
    width: 100,
    height: 100,
    opacity: 1,
    flip: false,
    invert: false,
    bringToFront: false,
    ...value,
  };


  const update = (field: string, fieldValue: any) => {
    onChange({
      ...current,
      [field]: fieldValue,
    });
  };

  return (
    <div className="space-y-4">
      {/* Enable toggle */}
      <div className="flex items-center justify-between">
        <span className="text-xs text-gray-500 font-medium">Enable Shape Divider</span>
        <button
          type="button"
          onClick={() => update("enabled", !current.enabled)}
          className={`flex items-center justify-center px-3 py-1.5 rounded-lg border text-xs font-semibold cursor-pointer transition-all ${
            current.enabled
              ? "bg-fuchsia-600 text-white border-fuchsia-600 hover:bg-fuchsia-700"
              : "bg-white text-gray-700 border-gray-200 hover:bg-gray-50"
          }`}
        >
          {current.enabled ? "Enabled" : "Disabled"}
        </button>
      </div>

      {current.enabled && (
        <div className="space-y-4 pt-2 border-t border-gray-100">
          {/* Position Tab Switcher */}
          <div className="flex rounded border border-gray-200 overflow-hidden p-0.5 bg-gray-50">
            <button
              type="button"
              onClick={() => update("position", "top")}
              className={`flex-1 py-1 text-xs font-semibold rounded transition-all cursor-pointer border-none ${
                current.position === "top"
                  ? "bg-white text-gray-800 shadow-sm"
                  : "bg-transparent text-gray-400 hover:text-gray-600"
              }`}
            >
              Top
            </button>
            <button
              type="button"
              onClick={() => update("position", "bottom")}
              className={`flex-1 py-1 text-xs font-semibold rounded transition-all cursor-pointer border-none ${
                current.position === "bottom"
                  ? "bg-white text-gray-800 shadow-sm"
                  : "bg-transparent text-gray-400 hover:text-gray-600"
              }`}
            >
              Bottom
            </button>
          </div>

          {/* Type Selector Grid */}
          <div className="space-y-1.5">
            <span className="text-xs text-gray-500 font-medium">Type</span>
            <div className="grid grid-cols-2 gap-2 max-h-[220px] overflow-y-auto pr-1">
              {Object.entries(SHAPES).map(([key, shape]) => (
                <button
                  key={key}
                  type="button"
                  onClick={() => update("shape", key)}
                  className={`flex flex-col items-center gap-1.5 p-1.5 rounded border bg-white cursor-pointer hover:border-gray-300 hover:bg-gray-50/50 transition-all ${
                    current.shape === key
                      ? "border-fuchsia-500 ring-1 ring-fuchsia-500 bg-fuchsia-50/5"
                      : "border-gray-200"
                  }`}
                >
                  <div className="w-full h-10 bg-gray-100 flex items-center justify-center rounded overflow-hidden relative">
                    <svg
                      viewBox={shape.viewBox}
                      preserveAspectRatio="none"
                      className="w-full h-7 absolute bottom-0 fill-gray-400"
                    >
                      <path d={shape.path} />
                    </svg>
                  </div>
                  <span className="text-[10px] text-gray-600 font-medium truncate max-w-full">
                    {shape.name}
                  </span>
                </button>
              ))}
            </div>
          </div>

          {/* Color Type Switcher */}
          <div className="flex flex-col gap-1">
            <span className="text-xs text-gray-500 font-medium">Color Type</span>
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => update("colorType", "solid")}
                className={`flex-1 py-1.5 text-xs font-semibold rounded-lg border cursor-pointer transition-all ${
                  current.colorType !== "gradient"
                    ? "bg-fuchsia-600 text-white border-fuchsia-600 hover:bg-fuchsia-700"
                    : "bg-white text-gray-700 border-gray-200 hover:bg-gray-50"
                }`}
              >
                Classic
              </button>
              <button
                type="button"
                onClick={() => update("colorType", "gradient")}
                className={`flex-1 py-1.5 text-xs font-semibold rounded-lg border cursor-pointer transition-all ${
                  current.colorType === "gradient"
                    ? "bg-fuchsia-600 text-white border-fuchsia-600 hover:bg-fuchsia-700"
                    : "bg-white text-gray-700 border-gray-200 hover:bg-gray-50"
                }`}
              >
                Gradient
              </button>
            </div>
          </div>

          {current.colorType !== "gradient" ? (
            /* Color Picker */
            <ColorPickerPopup
              label="Color"
              value={current.color || "#ffffff"}
              onChange={(c: string) => update("color", c)}
            />
          ) : (
            /* Gradient Controls */
            <div className="space-y-3 pt-2 border-t border-gray-100">
              <ColorPickerPopup
                label="Color 1"
                value={current.gradient?.color1 || "#ffffff"}
                onChange={(c: string) => update("gradient", { ...current.gradient, color1: c })}
              />
              <div className="space-y-1">
                <span className="text-xs text-gray-500 font-medium">Location 1 (%)</span>
                <Slider
                  min={0}
                  max={100}
                  value={current.gradient?.location1 ?? 0}
                  onChange={(v: number) => update("gradient", { ...current.gradient, location1: v })}
                />
              </div>
              <ColorPickerPopup
                label="Color 2"
                value={current.gradient?.color2 || "#f5f5f5"}
                onChange={(c: string) => update("gradient", { ...current.gradient, color2: c })}
              />
              <div className="space-y-1">
                <span className="text-xs text-gray-500 font-medium">Location 2 (%)</span>
                <Slider
                  min={0}
                  max={100}
                  value={current.gradient?.location2 ?? 100}
                  onChange={(v: number) => update("gradient", { ...current.gradient, location2: v })}
                />
              </div>
              <div className="space-y-1">
                <span className="text-xs text-gray-500 font-medium">Angle (deg)</span>
                <Slider
                  min={0}
                  max={360}
                  value={current.gradient?.angle ?? 180}
                  onChange={(v: number) => update("gradient", { ...current.gradient, angle: v })}
                />
              </div>
            </div>
          )}

          {/* Width Slider */}
          <div className="space-y-1">
            <span className="text-xs text-gray-500 font-medium">Width (%)</span>
            <Slider
              min={100}
              max={300}
              value={current.width ?? 100}
              onChange={(w: number) => update("width", w)}
            />
          </div>

          {/* Height Slider */}
          <div className="space-y-1">
            <span className="text-xs text-gray-500 font-medium">Height (px)</span>
            <Slider
              min={10}
              max={500}
              value={current.height ?? 100}
              onChange={(h: number) => update("height", h)}
            />
          </div>

          {/* Opacity Slider */}
          <div className="space-y-1">
            <span className="text-xs text-gray-500 font-medium">Opacity</span>
            <Slider
              min={0}
              max={1}
              step={0.01}
              value={current.opacity ?? 1}
              onChange={(o: number) => update("opacity", o)}
            />
          </div>

          {/* Flips & Inverts */}
          <Toggle
            label="Flip Horizontal"
            value={current.flip || false}
            onChange={(f: boolean) => update("flip", f)}
          />
          <Toggle
            label="Invert Vertical"
            value={current.invert || false}
            onChange={(i: boolean) => update("invert", i)}
          />

          {/* Bring to Front */}
          <Toggle
            label="Bring to Front"
            value={current.bringToFront || false}
            onChange={(b: boolean) => update("bringToFront", b)}
          />
        </div>
      )}
    </div>
  );
}